public boolean canGoBatch()
{
    boolean  batch;
    batch =  next  canGoBatch();
    batch = false;
    return batch;
}

/// <summary>
/// Abhinav - Estimate Production order in parent entity
/// </summary>
void run()
{
    try
    {
        ttsbegin;
        next run();

        if(ETGCanadaParameters::find().EnableSubContractingPO)
        {
            ProdParmCostEstimation curParmCostEstimation = this.setProduction();
            ProdTable prodTable = this.initProdTable(curParmCostEstimation.ProdId);

            if(prodTable && prodTable.ETGIsSubContractingOrder && prodTable.ETGParentProdId)
            {
                changecompany(prodTable.ETGParentEntity)
                {
                    ProdTable prodTableParent = ProdTable::find(prodTable.ETGParentProdId);

                    ProdParmCostEstimation  parm;

                    ProdMultiCostEstimation estimation = ProdMultiCostEstimation::construct(null);
                    RunBaseMultiParm::initParm(estimation);

                    estimation.insert(prodTableParent, parm);
                    estimation.runOnServer();
                }
            }
        }
        ttscommit;
    }
    catch
    {
        ttsabort;
    }
}
